/* ===== BIBIGAME - 800+ Kart Verisi (Nadirlik Sistemi) ===== */
// Nadirlik: common(%60), rare(%25), epic(%12), legendary(%3)
// Kategoriler: food, danger, exploration, nature, social, magic, dark,
//   crafting, luck, rest, illness, milestone, kader
// Her kart 4 seçenekli, her seçenekte "result" anlatı metni (opsiyonel)

const CARDS = [];
let _cid = 0;

function _randomRarity() {
    const r = Math.random() * 100;
    if (r < 60) return 'common';
    if (r < 85) return 'rare';
    if (r < 97) return 'epic';
    return 'legendary';
}

function C(scenario, category, rarity, choices, daySpecific) {
    if (Array.isArray(rarity)) { choices = rarity; rarity = _randomRarity(); daySpecific = null; }
    else if (!rarity || typeof rarity !== 'string') { rarity = _randomRarity(); daySpecific = choices; choices = rarity; }

    const normalized = choices.map(function(c) {
        return {
            text: c.text || c.t || '',
            effects: c.effects || c.e || {},
            hint: c.hint || c.h || '',
            result: c.result || c.r || ''
        };
    });
    CARDS.push({
        id: 'card_' + String(++_cid).padStart(4,'0'),
        scenario, category, rarity,
        choices: normalized,
        daySpecific: daySpecific || 0
    });
}

// Mevcut kartlara rastgele nadirlik ata (geriye dönük uyumlu)
CARDS.forEach(function(card) {
    if (!card.rarity) card.rarity = _randomRarity();
    card.id = 'card_' + String(card.id.replace('card_','')).padStart(4,'0');
    card.choices.forEach(function(ch) { if (!ch.result) ch.result = ''; });
});
_cid = CARDS.length;

