C("Kum firtinasi yaklasiyor. Gokyuzu turuncu.","danger","common",[{t:"Siginak bul, hemen saklan",e:{},h:"Hizli",r:"Siginakta firtinayi atlattin."},{t:"Gozluk tak, disarida kal",e:{heart:-1,gold:2},h:"Cesur",r:"Firtinanin getirdigi altin tozunu topladin."},{t:"Kuma karsi duvar or",e:{wood:-2},h:"Muhendis",r:"Duvar firtinayi kesti."},{t:"Firtinanin gobegine yuru",e:{heart:-3,gold:5},h:"Deli",r:"Ortasinda hazine buldun!"}]);

