C("Dolunay var. Butun gece aydinlik. Kurtlar uluyor.","nature","common",[{t:"Ay isiginda yuru, geceyi yasa",e:{heart:1},h:"Gececi",r:"Ay isigi yolunu aydinlatti."},{t:"Kurt ulumalarina eslik et",e:{heart:1,gold:1},h:"Muzisyen",r:"Kurtlarla ulumak rahatlaticiymis."},{t:"Ayin altinda meditasyon yap",e:{heart:2},h:"Mistik",r:"Ay enerjisi seni doldurdu."},{t:"Kurtlari takip et, ne yapiyorlar",e:{gold:2},h:"Gozlemci",r:"Kurtlar ava cikmis. Onlari izledin."}]);

C("Cicek acmis kiraz agaci. Yapraklari ruzgarla dokuluyor.","nature","common",[{t:"Kirazlari topla, afiyetle ye",e:{food:2,heart:1},h:"Keyifli",r:"Kirazlar tatli ve sulu."},{t:"Agacin altinda uyu",e:{heart:2},h:"Romantik",r:"Yapraklarin altinda uyudun."},{t:"Agaci asila, cogalt",e:{food:3},h:"Cifci",r:"Agaci cogaltabilirsin."},{t:"Dallarindan tac yap",e:{heart:1},h:"Yaratici",r:"Guzel bir tac yaptin."}]);

C("Gokkusaginin bittigi yerde bir tas var. Uzerinde isimler yazili.","magic","rare",[{t:"Isimleri oku, kim bunlar",e:{gold:2},h:"Tarihci",r:"Eski kahramanlarin isimleri. Saygi dur."},{t:"Tasa ismini ekle",e:{heart:1},h:"Egoist",r:"Artik sen de listedesin."},{t:"Tasi kaldir, altinda ne var",e:{gold:5,heart:-1},h:"Defineci",r:"Tasin altinda kutsal bir sandik vardi."},{t:"Tasin etrafinda dans et",e:{heart:2},h:"Kutlayici",r:"Gokkusagi enerjisi seni sardi."}]);

C("Kendi kendine yanan bir mesale buldun. Ruzgarda sonmuyor.","magic","rare",[{t:"Mesaleyi yaninda tasi, isik gerekli",e:{wood:-1},h:"Pratik",r:"Mesale sonsuz isik veriyor."},{t:"Mesalenin buyusunu coz",e:{gold:3},h:"Buyucu",r:"Sonsuz alev buyusu. Not aldin."},{t:"Mesaleyi kutsal yere dik",e:{heart:2},h:"Kutsayici",r:"Kutsal mekan aydinlandi."},{t:"Mesaleyi suya at, ne olacak",e:{heart:-1},h:"Deneyci",r:"Mesale su altinda bile yandi!"}]);

C("Eski bir zindanin kapisi aralandi. Zincirler yerde.","dark","common",[{t:"Zindana gir, mahkumlarin izini sur",e:{gold:3,heart:-1},h:"Kaşif",r:"Mahkumlar kacmis ama esyalari kalmis."},{t:"Kapıyi kapat, cikis yok",e:{},h:"Korkak",r:"Kapattin. Iceriden gelen sesler kesildi."},{t:"Zincirleri topla, metal olarak kullan",e:{gold:2},h:"Pratik",r:"Zincirler kaliteli demirden."},{t:"Duvardaki yazilari oku",e:{gold:1},h:"Tarihci",r:"Yazilar mahkumlarin hikayeleri."}]);

C("Yeralti mezari buldun. Lahitin kapagi aralik.","dark","epic",[{t:"Lahiti ac, icine bak",e:{gold:7,heart:-2},h:"Mezar soyguncusu",r:"Lahitte kral hazinesi ve bir lanet."},{t:"Saygi goster, dua et",e:{heart:3},h:"Saygili",r:"Kralin ruhu seni kutsadi."},{t:"Lahiti kapat, mulurle",e:{heart:1},h:"Koruyucu",r:"Muhurledin. Ruh rahatsiz edilmemeli."},{t:"Mezari arastir, duvarlari incele",e:{gold:3},h:"Arkeolog",r:"Duvarlarda hazine haritasi var."}]);

C("Terk edilmis bir kutuphanenin mahzeninde zincirlenmis bir kitap.","dark","epic",[{t:"Zinciri kir, kitabi ac",e:{gold:5,heart:-2},h:"Cesur",r:"Kitap lanetli. Ama icindeki bilgi essiz."},{t:"Kitabi okuma, cok tehlikeli",e:{},h:"Tedbir",r:"Kitap kapali kaldi. Guvendesin."},{t:"Kitabin uzerindeki yazilari incele",e:{heart:1},h:"Dedektif",r:"Kitap bir seytani kovma kitabiymis."},{t:"Mahseni tamamen kapat, mulurle",e:{heart:2},h:"Muhafiz",r:"Mahsen mulurlendi. Kotuluk hapsedildi."}]);

C("Ruzgar ters yonden esiyor. Doganin duzeni bozulmus.","nature","rare",[{t:"Ruzgari takip et, kaynagini bul",e:{gold:3},h:"Kaşif",r:"Kaynak bir enerji girdabiymis."},{t:"Ruzgara karsi yuru, direncini test et",e:{heart:1},h:"Dayanikli",r:"Ruzgara karsi yurumek guclendirdi."},{t:"Ruzgar gulunu yap, enerjini topla",e:{heart:1,wood:1},h:"Mucit",r:"Ruzgar gulun kampina enerji verdi."},{t:"Ruzgari izle, sadece hisset",e:{heart:1},h:"Meditasyon",r:"Ruzgar sana fisildadi."}]);

C("Gece gokyuzunde iki ay var. Biri kirmizi.","magic","legendary",[{t:"Kirmizi ayin altinda buyu yap",e:{gold:10,heart:-2},h:"Buyucu",r:"Kirmizi ay buyusunu katladi."},{t:"Iki ayi da izle, not al",e:{heart:1,gold:2},h:"Astronom",r:"Bu fenomen yuzyilda bir olur."},{t:"Kirmizi aya bakarak dilek tut",e:{heart:3},h:"Romantik",r:"Dilegin kabul oldu. Kirmizi ay goz kirpti."},{t:"Uyu, iki ayin altinda ruyaya dal",e:{heart:2,gold:3},h:"Hayalperest",r:"Ruyanda iki ayin dans ettigini gordun."}]);

C("Yerin altindan gelen davul sesleri. Ritmik ve derin.","exploration","rare",[{t:"Sesi takip et, kaynagini bul",e:{gold:4,heart:-1},h:"Kaşif",r:"Yer altinda bir ritüel alani buldun."},{t:"Sen de ritme katil, dans et",e:{heart:3},h:"Dansci",r:"Dans transa soktu. Mistik deneyim."},{t:"Sesi kaydet, not al",e:{heart:1},h:"Arastirmaci",r:"Ritm bir mesaj iceriyor olabilir."},{t:"Sesi gormezden gel",e:{},h:"Umursamaz",r:"Ses devam etti ama sen yoluna gittin."}]);

